use super::Env;
use super::error::EvalError;
use super::quit;
#[cfg(unix)]
use super::tty;
use super::sexp::Sexp;
use std::path::{Path, PathBuf};
const BUILTIN_NAMES: &[&str] = &["vector","make-vector","nelisp--length-cons-cc","nelisp--recordp-cc","string-bytes","nl-jit-call-format-float","truncate","nelisp--syscall-canonicalize","nelisp--syscall-stat","nelisp--syscall-readdir","nelisp--syscall-read-file","nelisp--syscall",
    "symbol-function","fset","nelisp--push-frame","nelisp--pop-frame","nelisp--push-captured","nelisp--bind-local","nelisp--apply-builtin-dispatch","nelisp--set-use-elisp-apply","nelisp--apply-lambda-inner","funcall","apply","eval","signal","nelisp--write-stdout-bytes","nelisp--write-stderr-line",
    "read-stdin-bytes","nelisp--f64-trunc","nl-write-file","nl-make-directory","terminal-raw-mode-enter","terminal-raw-mode-leave","read-stdin-byte-available","_termios-saved-p","_raw-mode-hooks-installed-p","set-quit-flag","clear-quit-flag","quit-flag-pending-p","install-sigint-handler","_sigint-handler-installed-p",
    "install-winsize-handler","_winsize-handler-installed-p","terminal-take-winsize-changed","terminal-current-winsize","install-jobctrl-handlers","_jobctrl-handlers-installed-p","terminal-take-sigcont","nl-jit-call-i64-i64","nl-jit-call-ptr-ptr","nl-jit-call-syscall","nl-jit-call-out-1","nl-jit-call-out-2","nl-jit-call-out-1i","nl-jit-call-out-2i","nl-jit-call-float-float","nl-jit-call-float-cmp","nl-jit-call-float-unary","nl-fact-i64"];
macro_rules! builtin_dispatch {
    ($name:ident, $args:ident, $env:ident) => {
        match $name {
            "vector" => Ok(Sexp::vector($args.to_vec())),
            "make-vector" => { require_arity("make-vector", $args, 2, Some(2))?; let len = as_int("make-vector", &$args[0])?; if len < 0 { return Err(EvalError::arith(format!("make-vector: negative length {}", len))); } let mut r = Sexp::Nil; unsafe { crate::elisp_cc_spike::bi_make_vector(&$args[0], &$args[1], &mut r) }; Ok(r) },
            "nelisp--length-cons-cc" => { require_arity("nelisp--length-cons-cc", $args, 1, Some(1))?; match &$args[0] { Sexp::Cons(_) | Sexp::Nil => Ok(cc_slot_1(&$args[0], crate::elisp_cc_spike::length_cons)), other => Err(EvalError::wrong_type("sequencep", other.clone())) } },
            "nelisp--recordp-cc" => { require_arity("nelisp--recordp-cc", $args, 1, Some(1))?; Ok(cc_slot_1(&$args[0], crate::elisp_cc_spike::recordp)) },
            "string-bytes" => { require_arity("string-bytes", $args, 1, Some(1))?; let sv = match &$args[0] { Sexp::Str(_) => $args[0].clone(), Sexp::MutStr(rc) => Sexp::Str(rc.value.clone()), other => return Err(EvalError::wrong_type("string", other.clone())) }; Ok(cc_slot_1(&sv, crate::elisp_cc_spike::bi_string_bytes)) },
            "nl-jit-call-format-float" => crate::jit::bi_nl_jit_call_format_float($args),
            "truncate" => { require_arity("truncate", $args, 1, Some(1))?; match &$args[0] { Sexp::Int(_) => Ok(cc_slot_1(&$args[0], crate::elisp_cc_spike::truncate_int)), Sexp::Float(_) => Ok(cc_slot_1(&$args[0], crate::elisp_cc_spike::truncate_float)), other => Err(EvalError::wrong_type("numberp", other.clone())) } },
            "nelisp--syscall-canonicalize" => bi_syscall_canonicalize($args, $env), "nelisp--syscall-stat" => bi_syscall_stat($args, $env), "nelisp--syscall-readdir" => bi_syscall_readdir($args, $env),
            "nelisp--syscall-read-file" => bi_syscall_read_file($args, $env), "nelisp--syscall" => bi_syscall($args),
            "symbol-function" => { require_arity("symbol-function", $args, 1, Some(1))?; super::env_shim::bi_globals_op(&[Sexp::Symbol("get-function".into()), $args[0].clone()], $env) },
            "fset" => { require_arity("fset", $args, 2, Some(2))?; let resolved = match &$args[1] { Sexp::Symbol(s) => $env.lookup_function(s)?, other => other.clone() }; super::env_shim::bi_globals_op(&[Sexp::Symbol("set-function".into()), $args[0].clone(), resolved], $env) },
            "nelisp--push-frame" => { require_arity("nelisp--push-frame", $args, 0, Some(0))?; $env.frame_push_rust_direct(); Ok(Sexp::T) },
            "nelisp--pop-frame" => { require_arity("nelisp--pop-frame", $args, 0, Some(0))?; $env.frame_pop_rust_direct(); Ok(Sexp::T) },
            "nelisp--push-captured" => { require_arity("nelisp--push-captured", $args, 1, Some(1))?; $env.push_captured(&$args[0])?; Ok(Sexp::T) },
            "nelisp--bind-local" => { require_arity("nelisp--bind-local", $args, 2, Some(2))?; let name = match &$args[0] { Sexp::Symbol(s) => s.clone(), other => return Err(EvalError::wrong_type("symbol", other.clone())) }; $env.bind_local(&name, $args[1].clone()); Ok($args[1].clone()) },
            "nelisp--apply-builtin-dispatch" => { require_arity("nelisp--apply-builtin-dispatch", $args, 2, Some(2))?; let name = match &$args[0] { Sexp::Symbol(s) | Sexp::Str(s) => s.clone(), other => return Err(EvalError::wrong_type("symbol", other.clone())) }; dispatch(&name, &super::list_elements(&$args[1])?, $env) },
            "nelisp--set-use-elisp-apply" => { require_arity("nelisp--set-use-elisp-apply", $args, 1, Some(1))?; $env.use_elisp_apply = !matches!($args[0], Sexp::Nil); Ok(bool_sexp($env.use_elisp_apply)) },
            "nelisp--apply-lambda-inner" => { require_arity("nelisp--apply-lambda-inner", $args, 4, Some(4))?; let al = Sexp::list_from(&super::list_elements(&$args[3])?); let mut out = Sexp::Nil; let rc = unsafe { crate::elisp_cc_spike::apply_lambda_inner_call(&$args[0], &$args[1], &$args[2], &al, $env as *mut super::Env as *mut std::ffi::c_void, &mut out) }; if rc == 0 { Ok(out) } else { Err(super::consume_stashed_error($env, "nelisp--apply-lambda-inner")) } },
            "funcall" => { require_arity("funcall", $args, 1, None)?; let func = match &$args[0] { Sexp::Symbol(s) => $env.lookup_function(s)?, _ => $args[0].clone() }; super::apply_function(&func, &$args[1..], $env) },
            "apply" => { require_arity("apply", $args, 2, None)?; let func = match &$args[0] { Sexp::Symbol(s) => $env.lookup_function(s)?, _ => $args[0].clone() }; let mut aa: Vec<Sexp> = $args[1..$args.len()-1].to_vec(); aa.extend(super::list_elements(&$args[$args.len()-1])?); super::apply_function(&func, &aa, $env) },
            "eval" => { require_arity("eval", $args, 1, Some(2))?; super::eval(&$args[0], $env) },
            "signal" => { require_arity("signal", $args, 2, Some(2))?; let Sexp::Symbol(tag) = &$args[0] else { return Err(EvalError::wrong_type("symbolp", $args[0].clone())); }; let (q,a,w)=(Sexp::Symbol("quit".into()),Sexp::Symbol("arith-error".into()),Sexp::Symbol("wrong-type-argument".into())); let hd=|s:&Sexp|->Option<Sexp>{if let Sexp::Cons(b)=s{Some(b.car.clone())}else{None}};
                match unsafe{crate::elisp_cc_spike::bi_signal_dispatch(&$args[0],&q,&a,&w)}{0=>Err(EvalError::Quit),1=>Err(EvalError::arith(match hd(&$args[1]).as_ref().unwrap_or(&$args[1]){Sexp::Str(s)=>s.clone(),o=>format!("{o:?}")})),2=>Err(EvalError::wrong_type(match hd(&$args[1]){Some(Sexp::Symbol(s)|Sexp::Str(s))=>s.clone(),Some(o)=>format!("{o:?}"),None=>"argument".into()},match&$args[1]{Sexp::Cons(b)=>match&b.cdr{Sexp::Cons(c)=>c.car.clone(),o=>o.clone()},o=>o.clone()})),_=>Err(EvalError::user(tag.clone(),$args[1].clone()))} },
            "nelisp--write-stdout-bytes" => { use std::io::Write; require_arity("nelisp--write-stdout-bytes", $args, 1, Some(1))?; let bs = Sexp::Str($args[0].as_string_owned().ok_or_else(|| EvalError::wrong_type("stringp", $args[0].clone()))?); let rc = unsafe { crate::elisp_cc_spike::bi_write_stdout_bytes(&bs) }; if rc < 0 { return Err(EvalError::internal(format!("nelisp--write-stdout-bytes: write returned {rc}"))); } std::io::stdout().lock().flush().map_err(|e| EvalError::internal(format!("nelisp--write-stdout-bytes: {e}")))?; Ok($args[0].clone()) },
            "nelisp--write-stderr-line" => { use std::io::Write; require_arity("nelisp--write-stderr-line", $args, 1, Some(1))?; let bs = Sexp::Str($args[0].as_string_owned().ok_or_else(|| EvalError::wrong_type("stringp", $args[0].clone()))?); unsafe { let _ = crate::elisp_cc_spike::bi_write_stderr_line(&bs); } let mut e = std::io::stderr().lock(); let _ = e.write_all(b"\n"); let _ = e.flush(); Ok($args[0].clone()) },
            "read-stdin-bytes" => { require_arity("read-stdin-bytes", $args, 1, Some(1))?; let lim = match &$args[0] { Sexp::Int(n) if *n > 0 => *n as usize, o => return Err(EvalError::wrong_type("positive integer", o.clone())) }; let mut buf = vec![0u8; lim]; let rc = unsafe { crate::elisp_cc_spike::bi_read_stdin_bytes(buf.as_mut_ptr(), lim as i64) }; if rc < 0 { return Err(EvalError::internal(format!("read-stdin-bytes: read returned {}", rc))); } if rc == 0 { return Ok(Sexp::Nil); } buf.truncate((rc as usize).min(lim)); Ok(Sexp::Str(String::from_utf8_lossy(&buf).into_owned())) },
            "nelisp--f64-trunc" => { require_arity("nelisp--f64-trunc", $args, 3, Some(3))?; if !matches!($args[0], Sexp::Symbol(_)) { return Err(EvalError::wrong_type("symbol", $args[0].clone())); } let mut out = Sexp::Nil; unsafe { crate::elisp_cc_spike::f64_trunc_impl(&$args[0], &$args[1], &$args[2], &mut out) }; if matches!(out, Sexp::Nil) { Err(EvalError::internal("nelisp--f64-trunc: unknown mode")) } else { Ok(out) } },
            "nl-write-file" => { require_arity("nl-write-file", $args, 2, Some(2))?; let path = string_value(&$args[0])?; string_value(&$args[1])?; kernel_path_ok("nl-write-file", &path, unsafe { crate::elisp_cc_spike::bi_nl_write_file(&$args[0], &$args[1]) }) },
            "nl-make-directory" => { require_arity("nl-make-directory", $args, 1, Some(2))?; let path = string_value(&$args[0])?; kernel_path_ok("nl-make-directory", &path, unsafe { crate::elisp_cc_spike::bi_nl_make_directory(&$args[0]) as i32 as i64 }) },
            "terminal-raw-mode-enter" => { require_arity("terminal-raw-mode-enter", $args, 0, Some(0))?; #[cfg(unix)] { tty::raw_mode_enter()?; Ok(Sexp::T) } #[cfg(not(unix))] { Ok(Sexp::Nil) } },
            "terminal-raw-mode-leave" => { require_arity("terminal-raw-mode-leave", $args, 0, Some(0))?; #[cfg(unix)] { tty::raw_mode_leave()?; Ok(Sexp::T) } #[cfg(not(unix))] { Ok(Sexp::Nil) } },
            "read-stdin-byte-available" => { require_arity("read-stdin-byte-available", $args, 0, Some(1))?; let timeout_ms = match $args.get(0) { None|Some(Sexp::Nil) => 0i32, Some(Sexp::Int(n)) => *n as i32, Some(o) => return Err(EvalError::wrong_type("integer (timeout-ms)", o.clone())) }; #[cfg(unix)] { Ok(tty::stdin_byte_available(timeout_ms)?.map_or(Sexp::Nil, |b| Sexp::Int(b as i64))) } #[cfg(not(unix))] { let _=timeout_ms; Ok(Sexp::Nil) } },
            "_termios-saved-p" => { require_arity("_termios-saved-p", $args, 0, Some(0))?; #[cfg(unix)] { Ok(bool_sexp(tty::termios_saved_p())) } #[cfg(not(unix))] { Ok(Sexp::Nil) } },
            "_raw-mode-hooks-installed-p" => { require_arity("_raw-mode-hooks-installed-p", $args, 0, Some(0))?; #[cfg(unix)] { Ok(bool_sexp(tty::hooks_installed_p())) } #[cfg(not(unix))] { Ok(Sexp::Nil) } },
            "set-quit-flag" => { require_arity("set-quit-flag", $args, 0, Some(0))?; unsafe { crate::elisp_cc_spike::bi_set_quit_flag(quit::nl_quit_flag_ptr()); } Ok(Sexp::T) },
            "clear-quit-flag" => { require_arity("clear-quit-flag", $args, 0, Some(0))?; unsafe { crate::elisp_cc_spike::bi_clear_quit_flag(quit::nl_quit_flag_ptr()); } Ok(Sexp::T) },
            "quit-flag-pending-p" => { require_arity("quit-flag-pending-p", $args, 0, Some(0))?; Ok(bool_sexp(unsafe { crate::elisp_cc_spike::bi_quit_flag_pending_p(quit::nl_quit_flag_ptr()) } != 0)) },
            "install-sigint-handler" => { require_arity("install-sigint-handler", $args, 0, Some(0))?; quit::install_sigint_handler(); Ok(Sexp::T) },
            "_sigint-handler-installed-p" => { require_arity("_sigint-handler-installed-p", $args, 0, Some(0))?; Ok(bool_sexp(quit::sigint_handler_installed_p())) },
            "install-winsize-handler" => { require_arity("install-winsize-handler", $args, 0, Some(0))?; #[cfg(unix)] { tty::install_winsize_handler(); Ok(Sexp::T) } #[cfg(not(unix))] { Ok(Sexp::Nil) } },
            "_winsize-handler-installed-p" => { require_arity("_winsize-handler-installed-p", $args, 0, Some(0))?; #[cfg(unix)] { Ok(bool_sexp(tty::winsize_handler_installed_p())) } #[cfg(not(unix))] { Ok(Sexp::Nil) } },
            "terminal-take-winsize-changed" => { require_arity("terminal-take-winsize-changed", $args, 0, Some(0))?; #[cfg(unix)] { Ok(bool_sexp(tty::take_winsize_changed())) } #[cfg(not(unix))] { Ok(Sexp::Nil) } },
            "terminal-current-winsize" => { require_arity("terminal-current-winsize", $args, 0, Some(0))?; #[cfg(unix)] { Ok(tty::current_winsize().map_or(Sexp::Nil, |(c,r)| Sexp::cons(Sexp::Int(c as i64), Sexp::Int(r as i64)))) } #[cfg(not(unix))] { Ok(Sexp::Nil) } },
            "install-jobctrl-handlers" => { require_arity("install-jobctrl-handlers", $args, 0, Some(0))?; #[cfg(unix)] { tty::install_jobctrl_handlers(); Ok(Sexp::T) } #[cfg(not(unix))] { Ok(Sexp::Nil) } },
            "_jobctrl-handlers-installed-p" => { require_arity("_jobctrl-handlers-installed-p", $args, 0, Some(0))?; #[cfg(unix)] { Ok(bool_sexp(tty::jobctrl_handlers_installed_p())) } #[cfg(not(unix))] { Ok(Sexp::Nil) } },
            "terminal-take-sigcont" => { require_arity("terminal-take-sigcont", $args, 0, Some(0))?; #[cfg(unix)] { Ok(bool_sexp(tty::take_sigcont())) } #[cfg(not(unix))] { Ok(Sexp::Nil) } },
            "nl-jit-call-i64-i64" => crate::jit::bi_nl_jit_call_i64_i64($args), "nl-jit-call-ptr-ptr" => crate::jit::bi_nl_jit_call_ptr_ptr($args), "nl-jit-call-syscall" => crate::jit::bi_nl_jit_call_syscall($args), "nl-jit-call-out-1" => crate::jit::bi_nl_jit_call_out_1($args), "nl-jit-call-out-2" => crate::jit::bi_nl_jit_call_out_2($args),
            "nl-jit-call-out-1i" => crate::jit::bi_nl_jit_call_out_1i($args), "nl-jit-call-out-2i" => crate::jit::bi_nl_jit_call_out_2i($args), "nl-jit-call-float-float" => crate::jit::bi_nl_jit_call_float_float($args), "nl-jit-call-float-cmp" => crate::jit::bi_nl_jit_call_float_cmp($args), "nl-jit-call-float-unary" => crate::jit::bi_nl_jit_call_float_unary($args),
            "nl-fact-i64" => { require_arity("nl-fact-i64", $args, 1, Some(1))?; let Sexp::Int(_) = &$args[0] else { return Err(EvalError::wrong_type("integerp", $args[0].clone())); }; let mut out = Sexp::Nil; let rc = unsafe { crate::elisp_cc_spike::bi_nl_fact_i64(&$args[0], &mut out) }; if rc == 0 { Ok(out) } else { Err(EvalError::internal("nl-fact-i64: argument out of i64-safe range 0..=20")) } },
            _ => match $env.extern_builtins.get($name).cloned() { Some(f) => f($args, $env), None => Err(EvalError::unbound_fn($name)) }
        }
    };
}
pub fn install_builtins(env: &mut Env) { for n in BUILTIN_NAMES { env.mirror_set_function(n, Sexp::list_from(&[Sexp::Symbol("builtin".into()), Sexp::Symbol((*n).into())])); } }
pub fn dispatch(name: &str, args: &[Sexp], env: &mut Env) -> Result<Sexp, EvalError> { builtin_dispatch!(name, args, env) }
pub(crate) fn require_arity(name: &str, args: &[Sexp], min: usize, max: Option<usize>) -> Result<(), EvalError> { if args.len() < min || max.map_or(false, |m| args.len() > m) { Err(EvalError::wrong_arity(name, match max { Some(m) if m == min => min.to_string(), Some(m) => format!("{}-{}", min, m), None => format!("≥{}", min) }, args.len())) } else { Ok(()) } }
pub(crate) fn as_int(name: &str, v: &Sexp) -> Result<i64, EvalError> { match v { Sexp::Int(n) => Ok(*n), Sexp::Float(x) => Ok(*x as i64), other => Err(EvalError::wrong_type(format!("number ({} arg)", name), other.clone())) } }
fn string_value(v: &Sexp) -> Result<String, EvalError> { match v { Sexp::Str(s) | Sexp::Symbol(s) => Ok(s.clone()), Sexp::MutStr(rc) => Ok(rc.value.clone()), Sexp::Nil => Ok("nil".into()), Sexp::T => Ok("t".into()), o => Err(EvalError::wrong_type("stringp or symbolp", o.clone())) } }
fn resolve_path(arg: &Sexp, env: &Env) -> Result<PathBuf, EvalError> { let path = string_value(arg)?; let p = Path::new(&path); if p.is_absolute() { return Ok(p.to_path_buf()); } let base = match env.lookup_value("default-directory") { Ok(Sexp::Str(s)) => Some(s), _ => None }; Ok(base.as_deref().map(|b| Path::new(b).join(p)).or_else(|| std::env::current_dir().ok().map(|c| c.join(p))).unwrap_or_else(|| p.to_path_buf())) }
fn cc_slot_1(arg: &Sexp, f: unsafe fn(*const Sexp, *mut Sexp) -> *mut Sexp) -> Sexp { let mut slot = Sexp::Nil; unsafe { f(arg as *const _, &mut slot as *mut _) }; slot }
fn bool_sexp(v: bool) -> Sexp { if v { Sexp::T } else { Sexp::Nil } }
fn kernel_path_ok(name: &str, path: &str, rc: i64) -> Result<Sexp, EvalError> { if rc < 0 { Err(EvalError::internal(format!("{name}: {path}: kernel returned {rc}"))) } else { Ok(Sexp::T) } }
#[no_mangle] pub extern "C" fn nl_bi_f64_trunc_div_bits(n: *const Sexp, d: *const Sexp) -> i64 { let f=|p:*const Sexp|match unsafe{&*p}{Sexp::Int(i)=>*i as f64,Sexp::Float(v)=>*v,_=>0.0}; (f(n)/f(d)).to_bits() as i64 }
fn path_arg1(name: &str, args: &[Sexp], env: &mut Env) -> Result<(PathBuf, Sexp), EvalError> { require_arity(name,args,1,Some(1))?; let p=resolve_path(&args[0],env)?; Ok((p.clone(),Sexp::Str(p.to_string_lossy().into_owned()))) }
fn bi_syscall_canonicalize(args: &[Sexp], env: &mut Env) -> Result<Sexp, EvalError> { let (_, ps) = path_arg1("nelisp--syscall-canonicalize", args, env)?; let mut buf = vec![0u8; libc::PATH_MAX as usize]; if unsafe { crate::elisp_cc_spike::bi_syscall_canonicalize(&ps, buf.as_mut_ptr()) } == 0 { return Ok(Sexp::Nil); } Ok(Sexp::Str(String::from_utf8_lossy(&buf[..buf.iter().position(|&b|b==0).unwrap_or(buf.len())]).into_owned())) }
fn bi_syscall_read_file(args: &[Sexp], env: &mut Env) -> Result<Sexp, EvalError> { let (p, ps) = path_arg1("nelisp--syscall-read-file", args, env)?; let n = match std::fs::metadata(&p) { Ok(m) if m.is_file() => m.len() as usize, _ => return Ok(Sexp::Nil) }; if n == 0 { return Ok(Sexp::Str(String::new())); } let mut buf = vec![0u8; n]; let rc = unsafe { crate::elisp_cc_spike::bi_syscall_read_file(&ps, buf.as_mut_ptr(), n as i64) } as i32 as i64; if rc < 0 { return Ok(Sexp::Nil); } buf.truncate((rc as usize).min(n)); Ok(Sexp::Str(String::from_utf8_lossy(&buf).into_owned())) }
fn bi_syscall_stat(args: &[Sexp], env: &mut Env) -> Result<Sexp, EvalError> { let (_, ps) = path_arg1("nelisp--syscall-stat", args, env)?; let mut sb: libc::stat = unsafe { std::mem::zeroed() }; let rc = unsafe { crate::elisp_cc_spike::bi_syscall_stat(&ps, (&mut sb as *mut libc::stat) as *mut u8) }; Ok(Sexp::Symbol((if rc < 0 { "absent" } else { match sb.st_mode & libc::S_IFMT { m if m == libc::S_IFDIR => "directory", m if m == libc::S_IFREG => "file", _ => "absent" } }).into())) }
fn bi_syscall_readdir(args: &[Sexp], env: &mut Env) -> Result<Sexp, EvalError> { let (dir, ds) = path_arg1("nelisp--syscall-readdir", args, env)?; let Ok(rd) = std::fs::read_dir(&dir) else { return Ok(Sexp::Nil) }; Ok(Sexp::cons(ds, Sexp::list_from(&rd.filter_map(|e| e.ok()).map(|e| Sexp::Str(e.file_name().to_string_lossy().into_owned())).collect::<Vec<_>>()))) }
#[cfg(not(target_os = "linux"))] fn bi_syscall(_args: &[Sexp]) -> Result<Sexp, EvalError> { Err(EvalError::internal("nelisp--syscall: unsupported platform")) }
#[cfg(target_os = "linux")] fn bi_syscall(args: &[Sexp]) -> Result<Sexp, EvalError> {
    if args.is_empty() { return Err(EvalError::internal("nelisp--syscall: at least one argument (syscall nr / name) required")); }
    let nr = match &args[0] { Sexp::Int(n) => *n, Sexp::Symbol(s) => { let r = unsafe { crate::elisp_cc_spike::bi_syscall_resolve_nr(&args[0] as *const _) }; if r < 0 { return Err(EvalError::internal(format!("nelisp--syscall: unknown syscall name `{}'", s))); } r }, other => return Err(EvalError::wrong_type("syscall name (symbol) or number (integer)", other.clone())) };
    let mut a = [0i64; 6]; for (i, sexp) in args[1..].iter().enumerate().take(6) { a[i] = match sexp { Sexp::Int(n) => *n, Sexp::Nil => 0, Sexp::T => 1, other => return Err(EvalError::wrong_type(format!("integer (arg {} of nelisp--syscall)", i + 1), other.clone())) }; }; let r = unsafe { libc::syscall(nr, a[0], a[1], a[2], a[3], a[4], a[5]) }; Ok(Sexp::Int(if r == -1 { -(unsafe { *libc::__errno_location() } as i64) } else { r as i64 })) }
